export const THIRDS_TABLE = new Map<string, Record<string, string>>(RAW);

/**
 * Given the sorted group letters of the 8 qualifying third-place teams,
 * returns the slot assignment: D32matchId → groupLetter.
 * Returns undefined if the combination is not valid per FIFA rules.
 */
export function findThirdsAssignment(
  groupLetters: string[],
): Record<string, string> | undefined {
  const key = [...groupLetters].sort().join("");
  return THIRDS_TABLE.get(key);
}
